SELECT p.player_id, p.name, p.team, p.position, p.draft_year, p.draft_round, p.draft_pick
FROM players p
WHERE p.team = 'Rangers' AND p.service_time BETWEEN 1990 AND 1999;

SELECT name 
FROM players 
WHERE service_time >= 5 AND position = 'Pitcher';

SELECT fs.player_id, SUM(fs.fantasy_points) AS total_fantasy_points
FROM fantasy_stats AS fs
GROUP BY fs.player_id;
